package dev.harrison.rendacomcarro.finance.domain;
import dev.harrison.rendacomcarro.shared.domain.DecimalPolicy;import dev.harrison.rendacomcarro.vehicle.domain.Vehicle;import jakarta.persistence.*;import java.math.*;import java.time.*;import java.util.*;
@Entity @Table(name="financial_obligation") public class FinancialObligation {
 @Id private UUID id;@ManyToOne(fetch=FetchType.LAZY)@JoinColumn(name="vehicle_id")private Vehicle vehicle;@Enumerated(EnumType.STRING)@Column(name="obligation_type",nullable=false)private ObligationType type;@Enumerated(EnumType.STRING)@Column(nullable=false)private ObligationMode mode;@Column(nullable=false)private String creditor;@Column(name="principal_amount",nullable=false,precision=14,scale=2)private BigDecimal principalAmount;@Column(name="annual_interest_rate",nullable=false,precision=8,scale=6)private BigDecimal annualInterestRate;@Column(name="start_date",nullable=false)private LocalDate startDate;@Column(name="first_due_date")private LocalDate firstDueDate;@Column(name="term_months")private Integer termMonths;@Column(name="planned_installment",precision=14,scale=2)private BigDecimal plannedInstallment;@Column(name="current_balance",nullable=false,precision=14,scale=2)private BigDecimal currentBalance;@Enumerated(EnumType.STRING)@Column(nullable=false)private ObligationStatus status;@Column(name="monthly_target",precision=14,scale=2)private BigDecimal monthlyTarget;@Column(columnDefinition="text")private String notes;@Column(name="created_at",nullable=false)private LocalDateTime createdAt;
 protected FinancialObligation(){} public static FinancialObligation create(Vehicle v,ObligationType t,ObligationMode m,String creditor,BigDecimal principal,BigDecimal rate,LocalDate start,LocalDate firstDue,Integer months,BigDecimal installment,BigDecimal target,String notes){if(t==null||m==null||creditor==null||creditor.isBlank()||principal==null||principal.signum()<=0||start==null)throw new IllegalArgumentException("Obrigação inválida");if(m==ObligationMode.STRUCTURED&&(firstDue==null||months==null||months<=0))throw new IllegalArgumentException("Cronograma estruturado incompleto");FinancialObligation o=new FinancialObligation();o.id=UUID.randomUUID();o.vehicle=v;o.type=t;o.mode=m;o.creditor=creditor.trim();o.principalAmount=DecimalPolicy.money(principal);o.annualInterestRate=rate==null?BigDecimal.ZERO:rate;o.startDate=start;o.firstDueDate=firstDue;o.termMonths=months;o.plannedInstallment=installment==null?null:DecimalPolicy.money(installment);o.currentBalance=o.principalAmount;o.status=ObligationStatus.ACTIVE;o.monthlyTarget=target==null?null:DecimalPolicy.money(target);o.notes=notes;o.createdAt=LocalDateTime.now();return o;}
 public void applyPrincipal(BigDecimal amount){if(amount==null||amount.signum()<=0||amount.compareTo(currentBalance)>0)throw new IllegalArgumentException("Amortização inválida");currentBalance=DecimalPolicy.money(currentBalance.subtract(amount));if(currentBalance.signum()==0)status=ObligationStatus.PAID;}
 public UUID getId(){return id;}public Vehicle getVehicle(){return vehicle;}public ObligationType getType(){return type;}public ObligationMode getMode(){return mode;}public String getCreditor(){return creditor;}public BigDecimal getPrincipalAmount(){return principalAmount;}public BigDecimal getCurrentBalance(){return currentBalance;}public ObligationStatus getStatus(){return status;}public LocalDate getFirstDueDate(){return firstDueDate;}public Integer getTermMonths(){return termMonths;}public BigDecimal getAnnualInterestRate(){return annualInterestRate;}public BigDecimal getMonthlyTarget(){return monthlyTarget;}
}
